/* App shell */
.app {
  display: flex;
  flex-direction: column;
  height: 100vh;
  width: 100vw;
  overflow: hidden;
  background: var(--color-bg);
}

.app-body {
  display: flex;
  flex: 1;
  overflow: hidden;
}

/* ── Sidebar ─────────────────────────────────── */
.sidebar {
  width: var(--sidebar-width);
  min-width: var(--sidebar-width);
  background: var(--color-bg-sidebar);
  border-right: 1px solid var(--color-border);
  display: flex;
  flex-direction: column;
  overflow: hidden;
  user-select: none;
  transition:
    width 0.2s ease,
    min-width 0.2s ease,
    border-right-color 0.2s ease;
}

.sidebar.hidden {
  width: 0;
  min-width: 0;
  border-right-color: transparent;
}

.sidebar-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 12px 10px;
  border-bottom: 1px solid var(--color-border);
  min-height: 44px;
}

.sidebar-workspace-name {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-text-muted);
  text-transform: uppercase;
  letter-spacing: 0.05em;
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
}

.sidebar-open-btn {
  font-size: 16px;
  color: var(--color-text-faint);
  line-height: 1;
  padding: 2px 4px;
  border-radius: 4px;
  transition:
    color 0.15s,
    background 0.15s;
  flex-shrink: 0;
}

.sidebar-open-btn:hover {
  color: var(--color-accent);
  background: var(--color-accent-light);
}

.sidebar-header-actions {
  display: flex;
  align-items: center;
  gap: 4px;
}

.sidebar-action-btn {
  font-size: 16px;
  color: var(--color-text-faint);
  line-height: 1;
  padding: 2px 5px;
  border-radius: 4px;
  transition:
    color 0.15s,
    background 0.15s;
}

.sidebar-action-btn:hover {
  color: var(--color-accent);
  background: var(--color-accent-light);
}

.sidebar-tree {
  flex: 1;
  overflow-y: auto;
  padding: 6px 0;
}

.sidebar-dir {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 4px 0;
  width: 100%;
  font-size: 12px;
  font-weight: 600;
  color: var(--color-text-muted);
  text-transform: uppercase;
  letter-spacing: 0.04em;
  cursor: pointer;
  border-radius: 4px;
  transition: background 0.1s;
}

.sidebar-dir:hover {
  background: var(--color-bg-hover);
}

.sidebar-chevron {
  font-size: 9px;
  transition: none;
}

.sidebar-file {
  display: flex;
  align-items: center;
  gap: 5px;
  padding: 5px 10px 5px 0;
  font-size: 13.5px;
  color: var(--color-text);
  cursor: pointer;
  border-radius: 4px;
  transition: background 0.1s;
}

.sidebar-file:hover {
  background: var(--color-bg-hover);
}

.sidebar-file.selected {
  background: var(--color-bg-selected);
  color: var(--color-accent);
  font-weight: 500;
}

.sidebar-icon {
  font-size: 10px;
  color: var(--color-text-faint);
  flex-shrink: 0;
}

.sidebar-empty {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 14px;
  padding: 40px 20px;
  text-align: center;
  color: var(--color-text-faint);
  font-size: 13px;
}

.sidebar-open-workspace-btn {
  font-size: 13px;
  color: var(--color-accent);
  border: 1px solid var(--color-accent);
  border-radius: 6px;
  padding: 6px 14px;
  transition: background 0.15s;
}

.sidebar-open-workspace-btn:hover {
  background: var(--color-accent-light);
}

/* ── Editor Column ───────────────────────────── */
.editor-column {
  flex: 1;
  display: flex;
  flex-direction: column;
  overflow: hidden;
}

/* ── Properties Panel ────────────────────────── */
.properties-wrapper {
  position: relative;
  flex-shrink: 0;
  /* min-height keeps the toggle button visible when the panel is collapsed */
  min-height: 28px;
  border-bottom: 1px solid var(--color-border);
  transition: border-bottom-color 0.2s ease;
}

.properties-wrapper.panel-closed {
  border-bottom-color: transparent;
}

.properties-panel {
  background: var(--color-bg-sidebar);
  overflow: hidden;
  max-height: 56px;
  transition: max-height 0.2s ease;
}

.properties-panel.closed {
  max-height: 0;
}

.properties-inner {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 0 56px 0 24px;
  height: 56px;
  overflow: hidden;
}

.prop-field {
  display: flex;
  align-items: center;
  gap: 5px;
  flex-shrink: 0;
}

.prop-label {
  font-size: 11px;
  color: var(--color-text-faint);
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.prop-value {
  font-size: 12px;
  color: var(--color-text-muted);
}

.prop-title {
  font-size: 12px;
  font-weight: 600;
  color: var(--color-text);
}

.prop-tag {
  font-size: 11px;
  color: var(--color-accent);
  background: var(--color-accent-light);
  border-radius: 4px;
  padding: 1px 6px;
}

.prop-draft {
  font-size: 11px;
  font-weight: 600;
  color: var(--color-warning);
  background: var(--color-warning-light);
  border-radius: 4px;
  padding: 1px 6px;
  text-transform: uppercase;
  letter-spacing: 0.04em;
}

.properties-toggle {
  position: absolute;
  right: 10px;
  top: 50%;
  transform: translateY(-50%);
  font-size: 16px;
  color: var(--color-text-faint);
  padding: 2px 6px;
  border-radius: 4px;
  transition:
    color 0.15s,
    background 0.15s;
  line-height: 1;
}

.properties-toggle:hover {
  color: var(--color-accent);
  background: var(--color-accent-light);
}

/* ── Empty State ─────────────────────────────── */
.empty-state {
  flex: 1;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 12px;
  color: var(--color-text-faint);
  user-select: none;
}

.empty-state-title {
  font-family: var(--font-editor);
  font-size: 28px;
  font-weight: 400;
  color: var(--color-text-muted);
  letter-spacing: 0.02em;
}

.empty-state-hint {
  font-size: 13px;
  color: var(--color-text-faint);
}

.empty-state-btn {
  margin-top: 4px;
  font-size: 13px;
  color: var(--color-accent);
  border: 1px solid var(--color-accent);
  border-radius: 6px;
  padding: 6px 18px;
  transition: background 0.15s;
}

.empty-state-btn:hover {
  background: var(--color-accent-light);
}

.empty-state-shortcut {
  font-size: 11px;
  color: var(--color-text-faint);
  opacity: 0.6;
}

/* ── Status Bar ──────────────────────────────── */
.statusbar {
  height: var(--statusbar-height);
  background: var(--color-status-bg);
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 14px;
  flex-shrink: 0;
}

.statusbar-left {
  display: flex;
  align-items: center;
  gap: 7px;
}

.save-dot {
  width: 6px;
  height: 6px;
  border-radius: 50%;
  flex-shrink: 0;
  transition:
    background-color 0.3s ease,
    opacity 0.3s ease;
  opacity: 0;
}

.save-dot.unsaved {
  background: var(--color-warning);
  opacity: 1;
}

.save-dot.saved {
  opacity: 0;
}

.statusbar-file {
  font-size: 11.5px;
  color: var(--color-status-text);
  font-family: var(--font-ui);
}

.statusbar-words {
  font-size: 11.5px;
  color: var(--color-status-text);
  font-family: var(--font-ui);
}

.statusbar-right {
  display: flex;
  align-items: center;
  gap: 10px;
}

/* ── Toasts ──────────────────────────────────── */
.toast-container {
  position: fixed;
  bottom: calc(var(--statusbar-height) + 12px);
  left: 50%;
  transform: translateX(-50%);
  display: flex;
  flex-direction: column;
  gap: 6px;
  z-index: 1000;
  pointer-events: none;
}

.toast {
  background: var(--color-text);
  color: var(--color-bg);
  font-size: 12.5px;
  padding: 7px 16px;
  border-radius: 6px;
  white-space: nowrap;
  animation: toast-in 0.15s ease;
}

@keyframes toast-in {
  from {
    opacity: 0;
    transform: translateY(6px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.statusbar-theme-btn {
  font-size: 13px;
  color: var(--color-status-text);
  line-height: 1;
  padding: 2px 4px;
  border-radius: 4px;
  transition:
    color 0.15s,
    background 0.15s;
  flex-shrink: 0;
  opacity: 0.7;
}

.statusbar-theme-btn:hover {
  color: var(--color-accent);
  background: var(--color-accent-light);
  opacity: 1;
}

