  flex-direction: column;
  gap: 6px;
  z-index: 1000;
  pointer-events: none;
}

.toast {
  background: var(--color-text);
  color: var(--color-bg);
  font-size: 12.5px;
  padding: 7px 16px;
  border-radius: 6px;
  white-space: nowrap;
  animation: toast-in 0.15s ease;
}

@keyframes toast-in {
  from {
    opacity: 0;
    transform: translateY(6px);
  }
  to {
    opacity: 1;
    transform: translateY(0);
  }
}

.statusbar-theme-btn {
  font-size: 13px;
  color: var(--color-status-text);
  line-height: 1;
  padding: 2px 4px;
  border-radius: 4px;
  transition:
    color 0.15s,
    background 0.15s;
  flex-shrink: 0;
  opacity: 0.7;
}

.statusbar-theme-btn:hover {
  color: var(--color-accent);
  background: var(--color-accent-light);
  opacity: 1;
