  const [wordCount, setWordCount] = useState(0);
  const [parsedFrontmatter, setParsedFrontmatter] = useState<ParsedFrontmatter>({});
  const [propertiesOpen, setPropertiesOpen] = useState(true);
  const [sidebarVisible, setSidebarVisible] = useState(
    () => localStorage.getItem(SIDEBAR_VISIBLE_KEY) !== "false"
  );
  const [saveStatus, setSaveStatus] = useState<SaveStatus>("saved");
  const [toasts, setToasts] = useState<Toast[]>([]);
  const [modal, setModal] = useState<ModalState>(null);
  const [renamingPath, setRenamingPath] = useState<string | null>(null);

  const frontmatterRef = useRef<string>("");
  const selectedPathRef = useRef<string | null>(null);
  const saveTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null);
  // Stores the latest unsaved markdown so file switches can flush it
  const pendingMarkdownRef = useRef<string | null>(null);

  useEffect(() => {
    return () => {
      if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    };
  }, []);

  const toastIdRef = useRef(0);

  const showToast = useCallback((message: string) => {
    const id = ++toastIdRef.current;
    setToasts((prev) => [...prev, { id, message }]);
    setTimeout(() => {
      setToasts((prev) => prev.filter((t) => t.id !== id));
    }, 2000);
  }, []);

  const flushPendingSave = useCallback(async () => {
    if (!saveTimerRef.current) return;
    clearTimeout(saveTimerRef.current);
    saveTimerRef.current = null;

    const path = selectedPathRef.current;
    const markdown = pendingMarkdownRef.current;
    if (!path || markdown === null) return;

    const diskContent = joinFrontmatter(frontmatterRef.current, markdown);
    try {
      await invoke("write_file", { path, content: diskContent });
      // Only clear after a successful write; if new edits arrived, keep them
      if (pendingMarkdownRef.current === markdown) {
        pendingMarkdownRef.current = null;
        setSaveStatus("saved");
      }
    } catch (err) {
      console.error("Failed to flush pending save:", err);
      showToast("Failed to save — check console for details");
    }
  }, [showToast]);

  const handleCloseFile = useCallback(async () => {
    await flushPendingSave();
    setSelectedFile(null);
    setFileContent("");
    setWordCount(0);
    setParsedFrontmatter({});
    setSaveStatus("saved");
    frontmatterRef.current = "";
    selectedPathRef.current = null;
    pendingMarkdownRef.current = null;
  }, [flushPendingSave]);

  const refreshTree = useCallback(async (): Promise<FileNode[]> => {
    try {
      const updated = await invoke<FileNode[]>("list_workspace");
      setTree(updated);
      return updated;
    } catch (err) {
      console.error("Failed to refresh tree:", err);
      return [];
    }
  }, []);

  // Global keyboard shortcuts
  useEffect(() => {
    function onKeyDown(e: KeyboardEvent) {
      if (!e.metaKey && !e.ctrlKey) return;
      switch (e.key) {
        case "\\":
          e.preventDefault();
          setSidebarVisible((v) => {
            const next = !v;
            localStorage.setItem(SIDEBAR_VISIBLE_KEY, String(next));
            return next;
          });
          break;
        case "o":
          e.preventDefault();
          void handleOpenWorkspace();
          break;
        case "P":
          if (e.shiftKey) {
            e.preventDefault();
            setPropertiesOpen((v) => !v);
          }
          break;
        case "n":
          e.preventDefault();
          if (workspaceRoot) setModal({ type: "new-file", dirPath: workspaceRoot });
          break;
        case "s":
          e.preventDefault();
          void flushPendingSave();
          break;
        case "w":
          e.preventDefault();
          void handleCloseFile();
          break;
      }
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [flushPendingSave, handleCloseFile, handleOpenWorkspace, workspaceRoot]);

  const handleOpenWorkspace = useCallback(async () => {
    await flushPendingSave();
    const result = await invoke<WorkspaceResult | null>("open_workspace");
    if (result) {
      setTree(result.tree);
      setWorkspaceName(result.name);
      setWorkspaceRoot(result.treeRoot);
      setSelectedFile(null);
      setFileContent("");
      setWordCount(0);
      setParsedFrontmatter({});
      setSaveStatus("saved");
      frontmatterRef.current = "";
      selectedPathRef.current = null;
      pendingMarkdownRef.current = null;
    }
  }, [flushPendingSave]);

  async function handleSelectFile(node: FileNode) {
    await flushPendingSave();
    setWordCount(0);
    setParsedFrontmatter({});
    setSaveStatus("saved");
    const prevPath = selectedPathRef.current;
    selectedPathRef.current = node.path;
    pendingMarkdownRef.current = null;

    try {
      const raw = await invoke<string>("read_file", { path: node.path });
      if (selectedPathRef.current !== node.path) return;
      const { frontmatter, body } = parseFrontmatter(raw);
      frontmatterRef.current = frontmatter;
      setSelectedFile(node);
      setFileContent(body);
      setParsedFrontmatter(parseYamlFrontmatter(raw));
    } catch (err) {
      console.error("Failed to read file:", err);
      showToast("Failed to open file — check console for details");
      if (selectedPathRef.current === node.path) selectedPathRef.current = prevPath;
    }
  }

  function handleEditorChange(markdown: string) {
    if (!selectedFile) return;
    const pathToSave = selectedFile.path;
    setSaveStatus("unsaved");
    pendingMarkdownRef.current = markdown;
    if (saveTimerRef.current) clearTimeout(saveTimerRef.current);
    saveTimerRef.current = setTimeout(async () => {
      saveTimerRef.current = null;
      const snapshot = pendingMarkdownRef.current;
      if (snapshot === null) return;
      const diskContent = joinFrontmatter(frontmatterRef.current, snapshot);
      try {
        await invoke("write_file", { path: pathToSave, content: diskContent });
        if (pendingMarkdownRef.current === snapshot) {
          pendingMarkdownRef.current = null;
          setSaveStatus("saved");
        }
      } catch (err) {
        console.error("Failed to save file:", err);
        showToast("Failed to save — check console for details");
      }
    }, SAVE_DELAY_MS);
  }

  function findNode(nodes: FileNode[], path: string): FileNode | undefined {
    for (const n of nodes) {
      if (n.path === path) return n;
      if (n.children) {
        const found = findNode(n.children, path);
        if (found) return found;
      }
    }
  }

  async function handleNewFile(dirPath: string, filename: string) {
    setModal(null);
    const slug = filename.replace(/\.md$/, "");
    const filePath = `${dirPath}/${slug}.md`;
    const content = createAmytisFrontmatter(slug);
    try {
      await invoke("create_file", { path: filePath, content });
      const updated = await refreshTree();
      const newNode = findNode(updated, filePath);
      if (newNode) await handleSelectFile(newNode);
    } catch (err) {
      console.error("Failed to create file:", err);
      showToast(`Failed to create file: ${err}`);
    }
  }

  async function handleRename(node: FileNode, newName: string) {
    setRenamingPath(null);
    await flushPendingSave();
    const dir = node.path.substring(0, node.path.lastIndexOf("/"));
    const ext = node.extension ?? ".md";
    const newPath = `${dir}/${newName}${newName.endsWith(ext) ? "" : ext}`;
    try {
      await invoke("rename_file", { oldPath: node.path, newPath });
      const updated = await refreshTree();
      if (selectedFile?.path === node.path) {
        const renamed = findNode(updated, newPath);
        if (renamed) {
          selectedPathRef.current = newPath;
          setSelectedFile(renamed);
        }
      }
    } catch (err) {
      console.error("Failed to rename file:", err);
      showToast(`Failed to rename: ${err}`);
    }
  }

  async function handleDelete(node: FileNode) {
    const confirmed = window.confirm(`Move "${node.name}" to Trash?`);
    if (!confirmed) return;
    try {
      await invoke("trash_file", { path: node.path });
      if (selectedFile?.path === node.path) await handleCloseFile();
      await refreshTree();
    } catch (err) {
      console.error("Failed to delete file:", err);
      showToast(`Failed to delete: ${err}`);
    }
  }

  async function handleFieldChange(key: string, value: FrontmatterValue) {
    if (!selectedFile) return;
    const updated = { ...parsedFrontmatter, [key]: value };
    setParsedFrontmatter(updated);
    const newFrontmatter = serializeFrontmatter(updated);
    frontmatterRef.current = newFrontmatter;

    let body: string;
    if (pendingMarkdownRef.current !== null) {
      body = pendingMarkdownRef.current;
    } else {
      try {
        const raw = await invoke<string>("read_file", { path: selectedFile.path });
        body = parseFrontmatter(raw).body;
      } catch (err) {
        console.error("Failed to read file body for frontmatter update:", err);
        showToast("Failed to load file — check console for details");
        return;
      }
    }

    try {
      await invoke("write_file", {
        path: selectedFile.path,
        content: joinFrontmatter(newFrontmatter, body),
      });
    } catch (err) {
      console.error("Failed to save frontmatter:", err);
      showToast("Failed to save — check console for details");
    }
  }

  const hasFrontmatter = Object.keys(parsedFrontmatter).length > 0;

  return (
    <div className="app">
      <div className="app-body">
        <Sidebar
          tree={tree}
          selectedPath={selectedFile?.path ?? null}
          renamingPath={renamingPath}
          visible={sidebarVisible}
          workspaceName={workspaceName}
          workspaceRoot={workspaceRoot}
          onSelect={handleSelectFile}
          onOpenWorkspace={handleOpenWorkspace}
          onNewFile={(dirPath) => setModal({ type: "new-file", dirPath })}
          onRename={handleRename}
          onDelete={handleDelete}
          onStartRename={setRenamingPath}
          onCancelRename={() => setRenamingPath(null)}
        />
        <div className="editor-column">
          {selectedFile && hasFrontmatter && (
            <PropertiesPanel
              frontmatter={parsedFrontmatter}
              isOpen={propertiesOpen}
              onToggle={() => setPropertiesOpen((v) => !v)}
              onFieldChange={handleFieldChange}
            />
          )}
          {selectedFile ? (
            <Editor
              key={selectedFile.path}
              content={fileContent}
              onWordCount={setWordCount}
              onChange={handleEditorChange}
            />
          ) : (
            <EmptyState workspaceOpen={tree.length > 0} onOpenWorkspace={handleOpenWorkspace} />
          )}
        </div>
      </div>
      <StatusBar
        fileName={selectedFile?.name ?? null}
        wordCount={wordCount}
        resolvedTheme={resolvedTheme}
        saveStatus={saveStatus}
        onToggleTheme={() => setPreference(resolvedTheme === "dark" ? "light" : "dark")}
      />
      {toasts.length > 0 && (
        <div className="toast-container">
          {toasts.map((t) => (
            <div key={t.id} className="toast">
              {t.message}
            </div>
          ))}
        </div>
      )}
      {modal?.type === "new-file" && (
        <InputModal
          title="New file"
          placeholder="filename"
          confirmLabel="Create"
          onConfirm={(name) => handleNewFile(modal.dirPath, name)}
          onCancel={() => setModal(null)}
        />
      )}
    </div>
  );
}

export default App;

import { useRef, useState } from "react";
import type { FrontmatterValue, ParsedFrontmatter } from "../lib/frontmatter";

interface PropertiesPanelProps {
  frontmatter: ParsedFrontmatter;
  isOpen: boolean;
  onToggle: () => void;
  onFieldChange?: (key: string, value: FrontmatterValue) => void;
}

function formatDate(value: string): string {
  try {
    return new Intl.DateTimeFormat(undefined, { dateStyle: "medium" }).format(
      new Date(`${value}T00:00:00`)
    );
  } catch {
    return value;
  }
}

const FIELD_ORDER = ["title", "date", "tags", "draft"];

function sortedKeys(frontmatter: ParsedFrontmatter): string[] {
  const known = FIELD_ORDER.filter((k) => k in frontmatter);
  const rest = Object.keys(frontmatter)
    .filter((k) => !FIELD_ORDER.includes(k))
    .sort();
  return [...known, ...rest];
}

interface EditableValueProps {
  fieldKey: string;
  value: FrontmatterValue;
  onSave: (newValue: FrontmatterValue) => void;
}

function EditableValue({ fieldKey, value, onSave }: EditableValueProps) {
  const [editing, setEditing] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);

  // Represent the value as a string for the input
  const toInputString = (v: FrontmatterValue): string => {
    if (Array.isArray(v)) return v.join(", ");
    if (v === null || v === undefined) return "";
    return String(v);
  };

  const [draft, setDraft] = useState(toInputString(value));

  function startEdit() {
    setDraft(toInputString(value));
    setEditing(true);
    // Focus on next tick after render
    setTimeout(() => inputRef.current?.focus(), 0);
  }

  function commit() {
    setEditing(false);
    const trimmed = draft.trim();
    if (Array.isArray(value)) {
      // Parse comma-separated back to array
      const arr = trimmed
        ? trimmed
            .split(",")
            .map((t) => t.trim())
            .filter(Boolean)
        : [];
      onSave(arr);
    } else if (typeof value === "number") {
      const num = Number(trimmed);
      onSave(Number.isNaN(num) ? value : num);
    } else {
      onSave(trimmed || null);
    }
  }

  function cancel() {
    setEditing(false);
    setDraft(toInputString(value));
  }

  if (editing) {
    return (
      <input
        ref={inputRef}
        className="prop-edit-input"
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === "Enter") commit();
          else if (e.key === "Escape") cancel();
        }}
        onBlur={commit}
        // Prevent sidebar keyboard shortcuts from firing while editing
        onKeyUp={(e) => e.stopPropagation()}
      />
    );
  }

  // For tags: show tag chips, click any to edit
  if (fieldKey === "tags" && Array.isArray(value)) {
    return (
      <button
        type="button"
        className="prop-editable-area"
        onClick={startEdit}
        title="Click to edit"
      >
        {value.map((tag) => (
          <span key={tag} className="prop-tag">
            {tag}
          </span>
        ))}
        {value.length === 0 && <span className="prop-value prop-empty">add tags…</span>}
      </button>
    );
  }

  if (fieldKey === "date" && typeof value === "string") {
    return (
      <button
        type="button"
        className="prop-editable-area"
        onClick={startEdit}
        title="Click to edit"
      >
        <span className="prop-value">{formatDate(value)}</span>
      </button>
    );
  }

  if (fieldKey === "title") {
    return (
      <button
        type="button"
        className="prop-editable-area"
        onClick={startEdit}
        title="Click to edit"
      >
        <span className="prop-value prop-title">{String(value)}</span>
      </button>
    );
  }

  return (
    <button type="button" className="prop-editable-area" onClick={startEdit} title="Click to edit">
      <span className="prop-value">{String(value ?? "")}</span>
    </button>
  );
}

export function PropertiesPanel({
  frontmatter,
  isOpen,
  onToggle,
  onFieldChange,
}: PropertiesPanelProps) {
  const keys = sortedKeys(frontmatter);

  return (
    <div className={`properties-wrapper ${isOpen ? "" : "panel-closed"}`}>
      <div className={`properties-panel ${isOpen ? "open" : "closed"}`}>
        <div className="properties-inner">
          {keys.map((key) => {
            const val = frontmatter[key];
            if (val === null || val === undefined) return null;

            // Draft: toggle button, not a text field
            if (key === "draft") {
              return (
                <div key={key} className="prop-field">
                  <button
                    type="button"
                    className={`prop-draft ${val ? "" : "prop-draft-published"}`}
                    title={val ? "Click to publish" : "Click to mark as draft"}
                    onClick={() => onFieldChange?.(key, !val)}
                  >
                    {val ? "Draft" : "Published"}
                  </button>
                </div>
              );
            }

            if (key === "tags" && Array.isArray(val)) {
              return (
                <div key={key} className="prop-field">
                  <EditableValue
                    fieldKey={key}
                    value={val}
                    onSave={(v) => onFieldChange?.(key, v)}
                  />
                </div>
              );
            }

            if (key === "title") {
              return (
                <div key={key} className="prop-field">
                  <EditableValue
                    fieldKey={key}
                    value={val}
                    onSave={(v) => onFieldChange?.(key, v)}
                  />
                </div>
              );
            }

            if (key === "date" && typeof val === "string") {
              return (
                <div key={key} className="prop-field">
                  <span className="prop-label">date</span>
                  <EditableValue
                    fieldKey={key}
                    value={val}
                    onSave={(v) => onFieldChange?.(key, v)}
                  />
                </div>
              );
            }

            return (
              <div key={key} className="prop-field">
                <span className="prop-label">{key}</span>
                <EditableValue fieldKey={key} value={val} onSave={(v) => onFieldChange?.(key, v)} />
              </div>
            );
          })}
        </div>
      </div>
      <button
        type="button"
        className="properties-toggle"
        onClick={onToggle}
        title={isOpen ? "Hide properties" : "Show properties"}
        aria-label="Toggle properties panel"
      >
        {isOpen ? "›" : "‹"}
      </button>
    </div>
  );
}

