import { useEffect, useRef, useState } from "react";
import type { FileNode } from "../lib/types";

interface SidebarProps {
  tree: FileNode[];
  selectedPath: string | null;
  renamingPath: string | null;
  visible: boolean;
  workspaceName: string | null;
  workspaceRoot: string | null;
  onSelect: (node: FileNode) => void;
  onOpenWorkspace: () => void;
  onNewFile: (dirPath: string) => void;
  onRename: (node: FileNode, newName: string) => void;
  onDelete: (node: FileNode) => void;
  onStartRename: (path: string) => void;
  onCancelRename: () => void;
}

interface FileItemProps {
  node: FileNode;
  depth: number;
  selectedPath: string | null;
  renamingPath: string | null;
  onSelect: (node: FileNode) => void;
  onNewFile: (dirPath: string) => void;
  onRename: (node: FileNode, newName: string) => void;
  onDelete: (node: FileNode) => void;
  onStartRename: (path: string) => void;
  onCancelRename: () => void;
}

function FileItem({
  node,
  depth,
  selectedPath,
  renamingPath,
  onSelect,
  onNewFile,
  onRename,
  onDelete,
  onStartRename,
  onCancelRename,
}: FileItemProps) {
  const [expanded, setExpanded] = useState(true);
  const isSelected = node.path === selectedPath;
  const isRenaming = renamingPath === node.path;
  const isMarkdown = node.extension === ".md" || node.extension === ".mdx";
  const baseName = node.name.replace(/\.mdx?$/, "");
  const [renameValue, setRenameValue] = useState(baseName);
  const renameRef = useRef<HTMLInputElement>(null);
  const indent = `${12 + depth * 14}px`;

  useEffect(() => {
    if (isRenaming) {
      setRenameValue(baseName);
      renameRef.current?.focus();
      renameRef.current?.select();
    }
  }, [isRenaming, baseName]);

  if (node.isDirectory) {
    return (
      <div>
        <div className="sidebar-dir-row" style={{ paddingLeft: indent }}>
          <button type="button" className="sidebar-dir" onClick={() => setExpanded((v) => !v)}>
            <span className="sidebar-icon sidebar-chevron">{expanded ? "▾" : "▸"}</span>
            {node.name}
          </button>
          <button
            type="button"
            className="sidebar-dir-action"
            title="New file here"
            onClick={() => onNewFile(node.path)}
          >
            +
          </button>
        </div>
        {expanded &&
          node.children?.map((child) => (
            <FileItem
              key={child.path}
              node={child}
              depth={depth + 1}
              selectedPath={selectedPath}
              renamingPath={renamingPath}
              onSelect={onSelect}
              onNewFile={onNewFile}
              onRename={onRename}
              onDelete={onDelete}
              onStartRename={onStartRename}
              onCancelRename={onCancelRename}
            />
          ))}
      </div>
    );
  }

  if (!isMarkdown) return null;

  if (isRenaming) {
    return (
      <div className="sidebar-rename-row" style={{ paddingLeft: indent }}>
        <input
          ref={renameRef}
          className="sidebar-rename-input"
          value={renameValue}
          onChange={(e) => setRenameValue(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === "Enter" && renameValue.trim()) {
              onRename(node, renameValue.trim());
            } else if (e.key === "Escape") {
              onCancelRename();
            }
          }}
          onBlur={() => {
            if (renameValue.trim()) onRename(node, renameValue.trim());
            else onCancelRename();
          }}
        />
      </div>
    );
  }

  return (
    <div className={`sidebar-file-row ${isSelected ? "selected" : ""}`}>
      <button
        type="button"
        className="sidebar-file"
        style={{ paddingLeft: indent }}
        onClick={() => onSelect(node)}
        onDoubleClick={() => onStartRename(node.path)}
        onKeyDown={(e) => {
          if (e.key === "F2") onStartRename(node.path);
        }}
      >
        <span className="sidebar-icon">◦</span>
        {baseName}
      </button>
      <button
        type="button"
        className="sidebar-delete-btn"
        title="Move to Trash"
        onClick={(e) => {
          e.stopPropagation();
          onDelete(node);
        }}
      >
        ✕
      </button>
    </div>
  );
}

export function Sidebar({
  tree,
  selectedPath,
  renamingPath,
  visible,
  workspaceName,
  workspaceRoot,
  onSelect,
  onOpenWorkspace,
  onNewFile,
  onRename,
  onDelete,
  onStartRename,
  onCancelRename,
}: SidebarProps) {
  return (
    <div className={`sidebar ${visible ? "" : "hidden"}`}>
      <div className="sidebar-header">
        <span className="sidebar-workspace-name">{workspaceName ?? "No workspace"}</span>
        <div className="sidebar-header-actions">
          {workspaceRoot && (
            <button
              type="button"
              className="sidebar-action-btn"
              title="New file (⌘N)"
              onClick={() => onNewFile(workspaceRoot)}
            >
              +
            </button>
          )}
          <button
            type="button"
            className="sidebar-open-btn"
            onClick={onOpenWorkspace}
            title="Open workspace"
          >
            ⊕
          </button>
        </div>
      </div>

      <div className="sidebar-tree">
        {tree.length === 0 ? (
          <div className="sidebar-empty">
            <p>No workspace open.</p>
            <button type="button" className="sidebar-open-workspace-btn" onClick={onOpenWorkspace}>
              Open folder
            </button>
          </div>
        ) : (
          tree.map((node) => (
            <FileItem
              key={node.path}
              node={node}
              depth={0}
              selectedPath={selectedPath}
              renamingPath={renamingPath}
              onSelect={onSelect}
              onNewFile={onNewFile}
              onRename={onRename}
              onDelete={onDelete}
              onStartRename={onStartRename}
              onCancelRename={onCancelRename}
            />
          ))
        )}
      </div>
    </div>
  );
}

import { useEffect, useRef, useState } from "react";
import type { FrontmatterValue, ParsedFrontmatter } from "../lib/frontmatter";

interface PropertiesPanelProps {
  frontmatter: ParsedFrontmatter;
  isOpen: boolean;
  onToggle: () => void;
  onFieldChange?: (key: string, value: FrontmatterValue) => void;
}

function formatDate(value: string): string {
  try {
    return new Intl.DateTimeFormat(undefined, { dateStyle: "medium" }).format(
      new Date(`${value}T00:00:00`)
    );
  } catch {
    return value;
  }
}

const FIELD_ORDER = ["title", "date", "tags", "draft"];

function toInputString(v: FrontmatterValue): string {
  if (Array.isArray(v)) return v.join(", ");
  if (v === null || v === undefined) return "";
  return String(v);
}

function sortedKeys(frontmatter: ParsedFrontmatter): string[] {
  const known = FIELD_ORDER.filter((k) => k in frontmatter);
  const rest = Object.keys(frontmatter)
    .filter((k) => !FIELD_ORDER.includes(k))
    .sort();
  return [...known, ...rest];
}

interface EditableValueProps {
  fieldKey: string;
  value: FrontmatterValue;
  onSave: (newValue: FrontmatterValue) => void;
}

function EditableValue({ fieldKey, value, onSave }: EditableValueProps) {
  const [editing, setEditing] = useState(false);
  const inputRef = useRef<HTMLInputElement>(null);
  const [draft, setDraft] = useState(toInputString(value));

  // Sync draft when value is updated externally (e.g. frontmatter written from disk)
  useEffect(() => {
    if (!editing) {
      setDraft(toInputString(value));
    }
  }, [value, editing]);

  function startEdit() {
    setDraft(toInputString(value));
    setEditing(true);
    // Focus on next tick after render
    setTimeout(() => inputRef.current?.focus(), 0);
  }

  function commit() {
    setEditing(false);
    const trimmed = draft.trim();
    if (Array.isArray(value)) {
      // Parse comma-separated back to array
      const arr = trimmed
        ? trimmed
            .split(",")
            .map((t) => t.trim())
            .filter(Boolean)
        : [];
      onSave(arr);
    } else if (typeof value === "number") {
      const num = Number(trimmed);
      onSave(Number.isNaN(num) ? value : num);
    } else {
      onSave(trimmed || null);
    }
  }

  function cancel() {
    setEditing(false);
    setDraft(toInputString(value));
  }

  if (editing) {
    return (
      <input
        ref={inputRef}
        className="prop-edit-input"
        value={draft}
        onChange={(e) => setDraft(e.target.value)}
        onKeyDown={(e) => {
          if (e.key === "Enter") commit();
          else if (e.key === "Escape") cancel();
        }}
        onBlur={commit}
        // Prevent sidebar keyboard shortcuts from firing while editing
        onKeyUp={(e) => e.stopPropagation()}
      />
    );
  }

  // For tags: show tag chips, click any to edit
  if (fieldKey === "tags" && Array.isArray(value)) {
    return (
      <button
        type="button"
        className="prop-editable-area"
        onClick={startEdit}
        title="Click to edit"
      >
        {value.map((tag) => (
          <span key={tag} className="prop-tag">
            {tag}
          </span>
        ))}
        {value.length === 0 && <span className="prop-value prop-empty">add tags…</span>}
      </button>
    );
  }

  if (fieldKey === "date" && typeof value === "string") {
    return (
      <button
        type="button"
        className="prop-editable-area"
        onClick={startEdit}
        title="Click to edit"
      >
        <span className="prop-value">{formatDate(value)}</span>
      </button>
    );
  }

  if (fieldKey === "title") {
    return (
      <button
        type="button"
        className="prop-editable-area"
        onClick={startEdit}
        title="Click to edit"
      >
        <span className="prop-value prop-title">{String(value)}</span>
      </button>
    );
  }

  return (
    <button type="button" className="prop-editable-area" onClick={startEdit} title="Click to edit">
      <span className="prop-value">{String(value ?? "")}</span>
    </button>
  );
}

export function PropertiesPanel({
  frontmatter,
  isOpen,
  onToggle,
  onFieldChange,
}: PropertiesPanelProps) {
  const keys = sortedKeys(frontmatter);

  return (
    <div className={`properties-wrapper ${isOpen ? "" : "panel-closed"}`}>
      <div className={`properties-panel ${isOpen ? "open" : "closed"}`}>
        <div className="properties-inner">
          {keys.map((key) => {
            const val = frontmatter[key];
            if (val === null || val === undefined) return null;

            // Draft: toggle button, not a text field
            if (key === "draft") {
              return (
                <div key={key} className="prop-field">
                  <button
                    type="button"
                    className={`prop-draft ${val ? "" : "prop-draft-published"}`}
                    title={val ? "Click to publish" : "Click to mark as draft"}
                    onClick={() => onFieldChange?.(key, !val)}
                  >
                    {val ? "Draft" : "Published"}
                  </button>
                </div>
              );
            }

            if (key === "tags" && Array.isArray(val)) {
              return (
                <div key={key} className="prop-field">
                  <EditableValue
                    fieldKey={key}
                    value={val}
                    onSave={(v) => onFieldChange?.(key, v)}
                  />
                </div>
              );
            }

            if (key === "title") {
              return (
                <div key={key} className="prop-field">
                  <EditableValue
                    fieldKey={key}
                    value={val}
                    onSave={(v) => onFieldChange?.(key, v)}
                  />
                </div>
              );
            }

            if (key === "date" && typeof val === "string") {
              return (
                <div key={key} className="prop-field">
                  <span className="prop-label">date</span>
                  <EditableValue
                    fieldKey={key}
                    value={val}
                    onSave={(v) => onFieldChange?.(key, v)}
                  />
                </div>
              );
            }

            return (
              <div key={key} className="prop-field">
                <span className="prop-label">{key}</span>
                <EditableValue fieldKey={key} value={val} onSave={(v) => onFieldChange?.(key, v)} />
              </div>
            );
          })}
        </div>
      </div>
      <button
        type="button"
        className="properties-toggle"
        onClick={onToggle}
        title={isOpen ? "Hide properties" : "Show properties"}
        aria-label="Toggle properties panel"
      >
        {isOpen ? "›" : "‹"}
      </button>
    </div>
  );
}

const isMac = navigator.platform.startsWith("Mac") || navigator.userAgent.includes("Mac");
const modKey = isMac ? "⌘" : "Ctrl+";

interface EmptyStateProps {
  workspaceOpen: boolean;
  onOpenWorkspace: () => void;
}

export function EmptyState({ workspaceOpen, onOpenWorkspace }: EmptyStateProps) {
  if (workspaceOpen) {
    return (
      <div className="empty-state">
        <p className="empty-state-hint">Select a file to start writing</p>
      </div>
    );
  }

  return (
    <div className="empty-state">
      <h2 className="empty-state-title">Ovid</h2>
      <p className="empty-state-hint">A writing space for Amytis content</p>
      <button type="button" className="empty-state-btn" onClick={onOpenWorkspace}>
        Open workspace
      </button>
      <p className="empty-state-shortcut">{modKey}O to open a folder</p>
    </div>
  );
}

